            {
                mGemmRunner = std::make_unique<CutlassFp4GemmRunner<half, FP4GemmType::W4A8_MXFP4_MXFP8>>();
            }
            else if (mfp4GemmType == FP4GemmType::W4A4_NVFP4_NVFP4)
