            if (mfp4GemmType == FP4GemmType::W4A8_MXFP4_MXFP8)
            {
                mGemmRunner = std::make_unique<CutlassFp4GemmRunner<__nv_bfloat16, FP4GemmType::W4A8_MXFP4_MXFP8>>();
            }
            else if (mfp4GemmType == FP4GemmType::W4A4_NVFP4_NVFP4)
